<div class="d-flex justify-content-between align-items-center mb-4"><div><h2 class="h3 fw-bold mb-1">Asignaciones docentes</h2><p class="text-muted mb-0">Asigna docentes a materias por curso y gestion.</p></div><a href="<?= e(url('/asignaciones-docentes/crear')) ?>" class="btn btn-primary">Nueva asignacion</a></div>
